mapper.select:
SELECT visitor_name
FROM visitor_vehicle
WHERE visitor_vehicle_id = #{visitorVehicleId}

SELECT CONCAT(visitor_name, ' (', IFNULL(purpose, '목적 없음'), ')')
FROM fixed_visitor_vehicle
WHERE fixed_id = #{fixedVisitorVehicleId}

SELECT log_id, license_plate, entry_type, vehicle_id, visitor_vehicle_id, fixed_visitor_vehicle_id, logged_at, CASE WHEN vehicle_id IS NOT NULL THEN '등록차량' WHEN visitor_vehicle_id IS NOT NULL THEN '방문차량' WHEN fixed_visitor_vehicle_id IS NOT NULL THEN '고정방문차량' ELSE '미등록차량' END AS vehicle_type FROM parking_log WHERE 1=1
AND license_plate LIKE CONCAT('%', #{licensePlate}, '%')
AND DATE(logged_at) >= #{startDate}
AND DATE(logged_at) <= #{endDate}
AND entry_type = #{entryType}
AND CASE WHEN vehicle_id IS NOT NULL THEN '등록차량' WHEN visitor_vehicle_id IS NOT NULL THEN '방문차량' WHEN fixed_visitor_vehicle_id IS NOT NULL THEN '고정방문차량' ELSE '미등록차량' END = #{vehicleType}
ORDER BY logged_at DESC LIMIT #{startIdx}, #{size}

SELECT COUNT(*)
FROM parking_log
WHERE 1=1

    AND license_plate LIKE CONCAT('%', #{licensePlate}, '%')


    AND DATE(logged_at) >= #{startDate}


    AND DATE(logged_at) <= #{endDate}


    AND entry_type = #{entryType}


    AND CASE
    WHEN vehicle_id IS NOT NULL THEN '등록차량'
    WHEN visitor_vehicle_id IS NOT NULL THEN '방문차량'
    WHEN fixed_visitor_vehicle_id IS NOT NULL THEN '고정방문차량'
    ELSE '미등록차량'
    END = #{vehicleType}
